// ---------------------------------------------------------------------------
// agent/services/label-backfill.js — recover strategy attribution for
// autopilot trades stuck in the edge-health "Manual / external" bucket.
//
// Root cause (already fixed going forward, agent/lib/trade-labels.js): an
// unrecognised strategy key used to encode as '-' in the broker label,
// which is permanent — the broker label itself can't be rewritten after the
// fact. But trades.thesis is generated by the SAME strategy module that
// placed the trade, with wording specific enough to be a real fingerprint
// (owner: "every trade must have a purpose for the edge" — this recovers
// the purpose from evidence that's still sitting in the DB, not a guess).
//
// Deliberately conservative: only fires on an EXACT, unambiguous substring
// that no other strategy's thesis template produces. Never overwrites an
// existing label_strategy. Anything that doesn't match a fingerprint stays
// null — genuinely unrecoverable, not silently invented.
// ---------------------------------------------------------------------------

// Verbatim fragments from each strategy's own thesis template (see the
// `strategy:`/`thesis:` pair in each file) — kept in sync by hand since
// there's no shared constant to import without coupling these modules.
//
// Extended 2026-07-22 (owner: only 4 of 10 strategies had a fingerprint —
// the other 6 were structurally unrecoverable into Edge Health's Manual/
// external bucket even though their thesis text sat right there in the DB).
// Each fragment below was checked against EVERY OTHER strategy's thesis
// template to confirm no cross-match — e.g. ema_pullback and vwap_trend both
// say "buying the pullback", so the fingerprint anchors on "EMA20 above/below
// EMA50" (vwap_trend's equivalent line says "VWAP line", never "EMA20").
const FINGERPRINTS = [
  { strategy: 'vp_value', re: /value-area (low|high)/i },       // vp-value.js
  { strategy: 'rsi2_reversion', re: /RSI\(2\)/ },                // rsi2-reversion.js
  { strategy: 'vwap_trend', re: /VWAP line/i },                  // vwap-trend.js
  { strategy: 'fib_confluence', re: /Fibonacci confluence/i },   // fib-confluence.js
  { strategy: 'fib_618_fade', re: /61\.8% Fib fade/ },           // fib-strategy.js
  { strategy: 'inv_cup_handle', re: /Inverted Cup & Handle breakdown/ }, // cup-handle.js (dir=-1) — checked BEFORE cup_handle below, since its text contains "Cup & Handle" as a substring
  { strategy: 'cup_handle', re: /Cup & Handle breakout/ },       // cup-handle.js (dir=1)
  { strategy: 'ema_pullback', re: /EMA20 (above|below) EMA50/ }, // ema-pullback.js
  { strategy: 'donchian_breakout', re: /range height/i },        // donchian-breakout.js
  { strategy: 'rsi_meanrev', re: /50-bar average/ },             // rsi-meanrev.js
]

/**
 * @param {import('better-sqlite3').Database} db
 * @returns {{ scanned: number, updated: number, byStrategy: Record<string, number> }}
 */
export function backfillLabelStrategy(db) {
  const rows = db.prepare(`
    SELECT id, thesis FROM trades
    WHERE label_strategy IS NULL AND thesis IS NOT NULL AND source = 'autopilot'
  `).all()

  const update = db.prepare(`UPDATE trades SET label_strategy = ? WHERE id = ? AND label_strategy IS NULL`)
  let updated = 0
  const byStrategy = {}
  const matches = []
  const tx = db.transaction(() => {
    for (const r of rows) {
      const hit = FINGERPRINTS.find(f => f.re.test(r.thesis))
      if (!hit) continue
      update.run(hit.strategy, r.id)
      updated++
      byStrategy[hit.strategy] = (byStrategy[hit.strategy] || 0) + 1
      matches.push({ tradeId: r.id, strategy: hit.strategy })
    }
    if (updated > 0) {
      db.prepare('INSERT INTO action_log (method, path, body) VALUES (?, ?, ?)').run(
        'LABEL_BACKFILL', '/actions/backfill-label-strategy',
        JSON.stringify({ scanned: rows.length, updated, byStrategy, matches }),
      )
    }
  })
  tx()

  return { scanned: rows.length, updated, byStrategy }
}
